// Eendigo AIOS agent specs — full role definitions for all 14 agents.
//
// Source: cards.json generated by Livio's planning doc
// (Eendigo_AIOS_Agent_Plan.docx). Inlined here so production deploys
// (Render) don't depend on any external file path.
//
// Each card is matched to an agent in the `agents` table by exact
// `name` equality (CEO ↔ CEO, COO ↔ COO, etc. — see seed.ts spec
// applier). When the data evolves, regenerate cards.json from the
// source doc and overwrite this file in one diff.

export interface AgentSpec {
  /** Must match agents.name exactly. */
  name: string;
  /** One-line role tagline + reports-to. Goes into agents.mission. */
  subtitle: string;
  /** Long-form mission paragraph. Folded into the comprehensive JD. */
  role: string;
  /** Each entry is prefixed with [AUTONOMOUS] or [HUMAN-APPROVED]. */
  responsibilities: string[];
  /** Concrete artefacts the agent produces, with cadence in parens. */
  deliverables: string[];
  /** OKR sets — usually 3 objectives, each with 2-4 key results. */
  okrs: { objective: string; krs: string[] }[];
  /** Capabilities the agent must have. */
  skills: string[];
  /** Domain knowledge the agent must hold. */
  knowledge: string[];
  /** Books / frameworks / courses the agent studies. */
  training: string[];
  /** Reusable document templates the agent owns or uses. */
  templates?: string[];
}

